def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    base_penalty = 30
    max_steps = 10
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        decay = 1.0
        additive_factor = 0.0
        for step in range(max_steps):
            if ratio > 1.2:
                score += base_penalty * decay * (1 + step * 0.1)
                break
            elif ratio < 0.00005:
                score += 0.05 * decay + step * 0.01
                continue
            exp_comp = np.exp(-ratio * (step + 1) * 1.5)
            tanh_comp = np.tanh(ratio * 15 * (step + 1))
            log_comp = np.log1p(ratio * 200) / (step + 3)
            sin_comp = (np.sin(ratio * np.pi * (step + 0.25)))**2
            step_score = (exp_comp + tanh_comp) * decay + log_comp * decay + sin_comp * decay
            if 0.1 < ratio < 0.4:
                step_score += (6 - step) * 0.4 * decay
            elif 0.5 < ratio < 0.85:
                step_score -= step * 0.7 * decay
            else:
                step_score += 0.15 * step * decay
            decay *= 0.7
            score += step_score
            if score > 20:
                break
        if ratio < 0.4:
            for k in range(4):
                additive_factor += ((0.6 / (k + 1)) * (1 - ratio)) ** 3
            score += additive_factor
        elif ratio > 0.75:
            for k in range(3):
                threshold = item * (1 + 0.15 * k)
                if capacity < threshold:
                    score += 4 * (k + 1)
                else:
                    score -= (k + 1) * 0.5
        if capacity < item * 0.9:
            score += base_penalty * 0.8
        elif capacity > item * 2.5:
            score /= 2.5
        if ratio == 1.0:
            score -= 5
        if capacity % 2 == 0:
            score *= 0.9
        else:
            score *= 1.1
        smoothing = 0
        for adj in [-1, 1]:
            neighbor = i + adj
            if 0 <= neighbor < len(bins):
                diff = abs(capacity - bins[neighbor])
                smoothing += diff / (1 + abs(ratio - item/bins[neighbor]))
        score += smoothing * 0.05
        priorities[i] = score
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return np.full_like(priorities, float('inf'))
    p_min = np.min(finite)
    p_max = np.max(finite)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = p_min * 300
        elif priorities[i] == p_min:
            priorities[i] = 0
        elif priorities[i] == p_max:
            priorities[i] *= 1.9
        else:
            priorities[i] = ((priorities[i] - p_min) / (p_max - p_min)) ** 1.5 * 30
    return priorities
